   141→                StorageOperationStats.getInstance().blockCacheReadStreamThroughput.add(MetricsLevel.INFO, rst.sizeInBytes());
   142→                retCf.complete(rst);
   143→            }
   144→        }, retCf, LOGGER, "read"));
   145→        return retCf;
   146→    }
   147→
   148→    public long nextReadOffset() {
   149→        return nextReadOffset;
   150→    }
   151→
   152→    public long lastAccessTimestamp() {
   153→        return lastAccessTimestamp;
   154→    }
   155→
   156→    public void close() {
   157→        closed = true;
   158→        List<Block> blocks = new ArrayList<>(blocksMap.values());
   159→        // The Block#markRead will immediately invoke after the Block is removed.
   160→        blocksMap.clear();
   161→        blocks.forEach(Block::markReadCompleted);
   162→    }
   163→
   164→    void read0(ReadContext ctx, final long startOffset, final long endOffset, final int maxBytes) {
   165→        // 1. get blocks
   166→        CompletableFuture<List<Block>> getBlocksCf = getBlocks(startOffset, endOffset, maxBytes, false);
   167→
   168→        // 2. wait block's data loaded
   169→        List<Block> blocks = new ArrayList<>();
   170→        CompletableFuture<Void> loadBlocksCf = getBlocksCf.thenCompose(blockList -> {
   171→            blocks.addAll(blockList);
   172→            return CompletableFuture.allOf(blockList.stream().map(block -> block.loadCf).toArray(CompletableFuture[]::new));
   173→        });
   174→
   175→        // if the cache is hit, the loadBlocks will be done immediately
   176→        if (!loadBlocksCf.isDone()) {
   177→            ctx.accessType = BLOCK_CACHE_MISS;
   178→        }
   179→
   180→        // 3. extract records from blocks
   181→        loadBlocksCf.thenAccept(nil -> {
   182→            ctx.blocks.addAll(blocks);
   183→            Optional<Block> failedBlock = blocks.stream().filter(block -> block.exception != null).findAny();
   184→            if (failedBlock.isPresent()) {
   185→                ctx.cf.completeExceptionally(failedBlock.get().exception);
   186→                return;
   187→            }
   188→            if (blocks.isEmpty()) {
   189→                ctx.cf.completeExceptionally(new AutoMQException(String.format("[UNEXPECTED] streamId=%d Get empty blocks [%s, %s) %s", streamId, startOffset, endOffset, maxBytes)));
   190→                return;
   191→            }
   192→            int remainingSize = maxBytes;
   193→            long nextStartOffset = startOffset;
   194→            long nextEndOffset;
   195→            boolean fulfill = false;
   196→            for (Block block : blocks) {
   197→                DataBlockIndex index = block.index;
   198→                if (nextStartOffset < index.startOffset() || nextStartOffset >= index.endOffset()) {
   199→                    String msg = String.format("[BUG] nextStartOffset:%d is not in the range of index:%d-%d", nextStartOffset, index.startOffset(), index.endOffset());
   200→                    LOGGER.error(msg);
   201→                    ctx.cf.completeExceptionally(new RuntimeException(msg));
   202→                    return;
   203→                }
   204→                nextEndOffset = Math.min(endOffset, index.endOffset());
   205→                List<StreamRecordBatch> newRecords = block.data.getRecords(nextStartOffset, nextEndOffset, remainingSize);
   206→                nextStartOffset = nextEndOffset;
   207→                remainingSize -= newRecords.stream().mapToInt(StreamRecordBatch::size).sum();
   208→                ctx.records.addAll(newRecords);
   209→                if (nextStartOffset >= endOffset || remainingSize <= 0) {
   210→                    fulfill = true;
   211→                    break;
   212→                }
   213→            }
   214→            if (fulfill) {
   215→                ctx.cf.complete(new ReadDataBlock(ctx.records, ctx.accessType));
   216→                StorageOperationStats.getInstance().readBlockCacheStats(ctx.accessType == BLOCK_CACHE_HIT).record(ctx.start.elapsedAs(TimeUnit.NANOSECONDS));
   217→            } else {
   218→                if (nextStartOffset == startOffset) {
   219→                    // The nextStartOffset is not changed. It means we can't read any more records from the blocks.
   220→                    // So we should fast fail to prevent infinite loop.
   221→                    ctx.cf.completeExceptionally(new AutoMQException("[UNEXPECTED] Can't read any record from the blocks"));
   222→                    return;
   223→                }
   224→                // The DataBlockIndex#size is not precise cause of the data block contains record header and data block header.
   225→                // So we may need to retry read to fulfill the endOffset or maxBytes
   226→                long finalNextStartOffset = nextStartOffset;
   227→                int finalRemainingSize = remainingSize;
   228→                // use async to prevent recursive call cause stack overflow
   229→                eventLoop.execute(() -> read0(ctx, finalNextStartOffset, endOffset, finalRemainingSize));
   230→            }
   231→        }).whenComplete((nil, ex) -> {
   232→            if (ex != null) {
   233→                ctx.cf.completeExceptionally(ex);
   234→            }
   235→        });
   236→    }
   237→
   238→    /**
   239→     * This method is only for unit testing.
   240→     * AfterReadTryReadaheadCf is empty, the task has been completed
   241→     * AfterReadTryReadaheadCf is not empty, the task may be completed
   242→     *
   243→     * @return afterReadTryReadaheadCf
   244→     */
   245→    @VisibleForTesting
   246→    CompletableFuture<Void> getAfterReadTryReadaheadCf() {
   247→        return afterReadTryReadaheadCf;
   248→    }
   249→
   250→    /**
   251→     * This method is only for unit testing.
   252→     * inflightReadaheadCf is empty, the task has been completed
   253→     * inflightReadaheadCf is not empty, the task may be completed
   254→     *
   255→     * @return readahead.inflightReadaheadCf
   256→     */
   257→    @VisibleForTesting
   258→    CompletableFuture<Void> getReadaheadInflightReadaheadCf() {
   259→        return readahead.inflightReadaheadCf;
   260→    }
   261→
   262→    void afterRead(ReadDataBlock readDataBlock, ReadContext ctx) {
   263→        List<StreamRecordBatch> records = readDataBlock.getRecords();
   264→        if (!records.isEmpty()) {
   265→            nextReadOffset = records.get(records.size() - 1).getLastOffset();
   266→        }
   267→        // clear unused blocks
   268→        Iterator<Map.Entry<Long, Block>> it = blocksMap.entrySet().iterator();
   269→        while (it.hasNext()) {
   270→            Block block = it.next().getValue();
   271→            if (block.index.endOffset() <= nextReadOffset) {
   272→                it.remove();
   273→                block.markReadCompleted();
   274→            } else {
   275→                break;
   276→            }
   277→        }
   278→        for (Block block : ctx.blocks) {
   279→            block.release();
   280→        }
   281→        // try readahead to speed up the next read
   282→        afterReadTryReadaheadCf = eventLoop.submit(() -> readahead.tryReadahead(readDataBlock.getCacheAccessType() == BLOCK_CACHE_MISS));
   283→        afterReadTryReadaheadCf.whenComplete((nil, ex) -> {
   284→            Throwable cause = FutureUtil.cause(ex);
   285→            if (cause != null && !isRecoverable(cause)) {
   286→                LOGGER.error("AfterRead failed", ex);
   287→            }
   288→            // help gc
   289→            afterReadTryReadaheadCf = null;
   290→        });
   291→    }
   292→
   293→    private CompletableFuture<List<Block>> getBlocks(long startOffset, long endOffset, int maxBytes,
   294→        boolean readahead) {
   295→        GetBlocksContext context = new GetBlocksContext(readahead);
   296→        try {
   297→            getBlocks0(context, startOffset, endOffset, maxBytes);
   298→        } catch (Throwable ex) {
   299→            context.cf.completeExceptionally(ex);
   300→        }
   301→        context.cf.exceptionally(ex -> {
   302→            context.blocks.forEach(Block::release);
   303→            return null;
   304→        });
   305→        return context.cf;
   306→    }
   307→
   308→    private void getBlocks0(GetBlocksContext ctx, long startOffset, long endOffset, int maxBytes) {
   309→        Long floorKey = blocksMap.floorKey(startOffset);
   310→        if (floorKey == null && !blocksMap.isEmpty()) {
   311→            if (ctx.readahead) {
   312→                // The user read may be faster than the readahead, and clear the read completed blocks.
   313→                ctx.cf.complete(ctx.blocks);
   314→                return;
   315→            } else {
   316→                LOGGER.error("[BUG] {} cannot find floor block for startOffset={}, the first block={}", this, startOffset, blocksMap.firstEntry());
   317→                throw new AutoMQException("[BUG] cannot find floor block");
   318→            }
   319→        }
   320→        CompletableFuture<Boolean> loadMoreBlocksCf;
   321→        int remainingSize = maxBytes;
   322→        if (floorKey == null || startOffset >= loadedBlockIndexEndOffset) {
   323→            loadMoreBlocksCf = loadMoreBlocksWithoutData(endOffset);
   324→        } else {
   325→            boolean firstBlock = true;
   326→            boolean fulfill = false;
   327→            for (Map.Entry<Long, Block> entry : blocksMap.tailMap(floorKey).entrySet()) {
   328→                Block block = entry.getValue();
   329→                long objectId = block.metadata.objectId();
   330→                if (!objectManager.isObjectExist(objectId)) {
   331→                    // The cached block's object maybe deleted by the compaction. So we need to check the object exist.
   332→                    ctx.cf.completeExceptionally(new ObjectNotExistException(objectId));
   333→                    return;
   334→                }
   335→                DataBlockIndex index = block.index;
   336→                if (!firstBlock || index.startOffset() == startOffset) {
   337→                    remainingSize -= index.size();
   338→                }
   339→                if (firstBlock) {
   340→                    firstBlock = false;
   341→                }
   342→                // after read the data will be return to the cache, so we need to reload the data every time
   343→                block = block.newBlockWithData(ctx.readahead);
   344→                ctx.blocks.add(block);
   345→                if ((endOffset != -1L && index.endOffset() >= endOffset) || remainingSize <= 0) {
   346→                    fulfill = true;
   347→                    break;
   348→                }
   349→            }
   350→            if (fulfill) {
   351→                ctx.cf.complete(ctx.blocks);
   352→                return;
   353→            } else {
   354→                loadMoreBlocksCf = loadMoreBlocksWithoutData(endOffset);
   355→            }
   356→        }
   357→        int finalRemainingSize = remainingSize;
   358→        // use async to prevent recursive call cause stack overflow
   359→        loadMoreBlocksCf.thenAcceptAsync(moreBlocks -> {
   360→            if (ctx.readahead) {
   361→                // If #loadMoreBlocksWithoutData result is empty, it means the stream is already loads to the end.
   362→                if (!moreBlocks) {
   363→                    ctx.cf.complete(ctx.blocks);
   364→                    return;
   365→                }
   366→            } else {
   367→                if (!moreBlocks && endOffset > loadedBlockIndexEndOffset) {
   368→                    String errMsg = String.format("[BUG] streamId=%s expect load blocks to endOffset=%s, " + "current loadedBlockIndexEndOffset=%s", streamId, endOffset, loadedBlockIndexEndOffset);
   369→                    ctx.cf.completeExceptionally(new AutoMQException(errMsg));
   370→                    return;
   371→                }
   372→            }
   373→            long nextStartOffset = ctx.blocks.isEmpty() ? startOffset : ctx.blocks.get(ctx.blocks.size() - 1).index.endOffset();
   374→            getBlocks0(ctx, nextStartOffset, endOffset, finalRemainingSize);
   375→        }, eventLoop).exceptionally(ex -> {
   376→            ctx.cf.completeExceptionally(ex);
   377→            return null;
   378→        });
   379→    }
   380→
   381→    /**
   382→     * Load more block indexes
   383→     *
   384→     * @return whether load more blocks
   385→     */
   386→    private CompletableFuture<Boolean> loadMoreBlocksWithoutData(long endOffset) {
   387→        long oldLoadedBlockIndexEndOffset = loadedBlockIndexEndOffset;
   388→        return loadMoreBlocksWithoutData0(endOffset).thenApply(nil -> loadedBlockIndexEndOffset != oldLoadedBlockIndexEndOffset);
   389→    }
   390→
   391→    private CompletableFuture<Void> loadMoreBlocksWithoutData0(long endOffset) {
   392→        if (inflightLoadIndexCf != null) {
   393→            return inflightLoadIndexCf.thenCompose(rst -> loadMoreBlocksWithoutData0(endOffset));
   394→        }
   395→        if (endOffset != -1L && endOffset <= loadedBlockIndexEndOffset) {
   396→            return CompletableFuture.completedFuture(null);
   397→        }
   398→        long currentBlocksEpoch = blocksEpoch;
   399→        inflightLoadIndexCf = new CompletableFuture<>();
   400→        long nextLoadingOffset = calWindowBlocksEndOffset();
   401→        AtomicLong nextFindStartOffset = new AtomicLong(nextLoadingOffset);
   402→        TimerUtil time = new TimerUtil();
   403→        // 1. get objects
   404→        CompletableFuture<List<S3ObjectMetadata>> getObjectsCf = objectManager.getObjects(streamId, nextLoadingOffset, endOffset, GET_OBJECT_STEP);
   405→        // 2. get block indexes from objects
   406→        CompletableFuture<Void> findBlockIndexesCf = getObjectsCf.whenComplete((rst, ex) -> {
   407→            StorageOperationStats.getInstance().getIndicesTimeGetObjectStats.record(time.elapsedAndResetAs(TimeUnit.NANOSECONDS));
   408→        }).thenComposeAsync(objects -> {
   409→            CompletableFuture<Void> prevCf = CompletableFuture.completedFuture(null);
   410→            for (S3ObjectMetadata objectMetadata : objects) {
   411→                // the object reader will be release in the whenComplete
   412→                @SuppressWarnings("resource") ObjectReader objectReader = objectReaderFactory.get(objectMetadata);
   413→                // invoke basicObjectInfo to warm up the objectReader
   414→                objectReader.basicObjectInfo();
   415→                prevCf = prevCf.thenCompose(nil -> {
   416→                    if (currentBlocksEpoch != blocksEpoch) {
   417→                        // The blocks are reset, we need to stop the load
   418→                        return CompletableFuture.completedFuture(null);
   419→                    }
   420→                    return objectReader.find(streamId, nextFindStartOffset.get(), -1L, Integer.MAX_VALUE).thenAcceptAsync(findRst -> {
   421→                        if (currentBlocksEpoch != blocksEpoch) {
   422→                            // The blocks are reset, we need to stop the load
   423→                            return;
   424→                        }
   425→                        findRst.streamDataBlocks().forEach(streamDataBlock -> {
   426→                            DataBlockIndex index = streamDataBlock.dataBlockIndex();
   427→                            Block block = new Block(objectMetadata, index);
   428→                            if (!putBlock(block)) {
   429→                                // After object compaction, the blocks get from different objectManager#getObjects maybe not continuous.
   430→                                throw new BlockNotContinuousException();
   431→                            }
   432→                            nextFindStartOffset.set(streamDataBlock.getEndOffset());
   433→                        });
   434→                    }, eventLoop);
   435→                }).whenComplete((nil, ex) -> objectReader.release());
   436→            }
   437→            return prevCf;
   438→        }, eventLoop);
   439→        findBlockIndexesCf.whenCompleteAsync((nil, ex) -> {
   440→            if (ex != null) {
   441→                inflightLoadIndexCf.completeExceptionally(ex);
   442→                return;
   443→            }
   444→            StorageOperationStats.getInstance().getIndicesTimeFindIndexStats.record(time.elapsedAs(TimeUnit.NANOSECONDS));
   445→            CompletableFuture<Void> cf = inflightLoadIndexCf;
   446→            inflightLoadIndexCf = null;
   447→            cf.complete(null);
   448→        }, eventLoop);
   449→        return inflightLoadIndexCf;
   450→    }
   451→
   452→    private long calWindowBlocksEndOffset() {
   453→        Map.Entry<Long, Block> lastBlockIndex = blocksMap.lastEntry();
   454→        if (lastBlockIndex != null) {
   455→            return Math.max(lastBlockIndex.getValue().index.endOffset(), nextReadOffset);
   456→        }
   457→        return nextReadOffset;
   458→    }
   459→
   460→    private void handleBlockFree(Block block) {
   461→        if (closed) {
   462→            return;
   463→        }
   464→        Block blockInMap = blocksMap.get(block.index.startOffset());
   465→        if (block == blockInMap) {
   466→            // The unread block is evicted; It means the cache is full, we need to reset the readahead.
   467→            readahead.reset();
   468→            READAHEAD_RESET_LOG_SUPPRESSOR.warn("The unread block is evicted, please increase the block cache size");
   469→        }
   470→    }
   471→
   472→    private void resetBlocks() {
   473→        List<Block> blocks = new ArrayList<>(blocksMap.values());
   474→        // The Block#markRead will immediately invoke after the Block is removed.
   475→        blocksMap.clear();
   476→        blocks.forEach(Block::markReadCompleted);
   477→        lastBlock = null;
   478→        loadedBlockIndexEndOffset = 0L;
   479→        blocksEpoch++;
   480→        BLOCKS_RESET_LOG_SUPPRESSOR.info("The stream reader's blocks are reset, cause of the object compaction");
   481→    }
   482→
   483→    /**
   484→     * Put block into the blocks
   485→     *
   486→     * @param block {@link Block}
   487→     * @return if the block is continuous to the last block, it will return true
   488→     */
   489→    private boolean putBlock(Block block) {
   490→        if (lastBlock == null) {
   491→            // The first block should contain the nextReadOffset
   492→            if (!(block.index.startOffset() <= nextReadOffset && block.index.endOffset() > nextReadOffset)) {
   493→                LOGGER.error("[BUG] The first block should contain the nextReadOffset, block={} nextReadOffset={}", block.index, nextReadOffset);
   494→                return false;
   495→            }
   496→        } else if (lastBlock.index.endOffset() != block.index.startOffset()) {
   497→            return false;
   498→        }
   499→        lastBlock = block;
   500→        blocksMap.put(block.index.startOffset(), block);
   501→        loadedBlockIndexEndOffset = block.index.endOffset();
   502→        return true;
   503→    }
   504→
   505→    @Override
   506→    public String toString() {
   507→        return "StreamReader{" + "reading=" + reading + ", nextReadOffset=" + nextReadOffset + '}';
   508→    }
   509→
   510→    private static boolean isRecoverable(Throwable cause) {
   511→        return cause instanceof ObjectNotExistException || cause instanceof NoSuchKeyException || cause instanceof BlockNotContinuousException;
   512→    }
   513→
   514→    static class GetBlocksContext {
   515→        final List<Block> blocks = new ArrayList<>();
   516→        final CompletableFuture<List<Block>> cf = new CompletableFuture<>();
   517→        final boolean readahead;
   518→
   519→        public GetBlocksContext(boolean readahead) {
   520→            this.readahead = readahead;
   521→        }
   522→    }
   523→
   524→    static class ReadContext {
   525→        final List<StreamRecordBatch> records = new LinkedList<>();
   526→        final List<Block> blocks = new ArrayList<>();
   527→        final CompletableFuture<ReadDataBlock> cf = new CompletableFuture<>();
   528→        CacheAccessType accessType = BLOCK_CACHE_HIT;
   529→        final TimerUtil start = new TimerUtil();
   530→    }
   531→
   532→    class Block {
   533→        final S3ObjectMetadata metadata;
   534→        final DataBlockIndex index;
   535→        DataBlock data;
   536→        DataBlock.FreeListenerHandle freeListenerHandle;
   537→
   538→        CompletableFuture<Void> loadCf;
   539→        Throwable exception;
   540→        boolean released = false;
   541→        boolean readCompleted = false;
   542→
   543→        public Block(S3ObjectMetadata metadata, DataBlockIndex index) {
   544→            this.metadata = metadata;
   545→            this.index = index;
   546→        }
   547→
   548→        // TODO: use different Block type, cause of the returned Block shouldn't have markReadCompleted method
   549→        public Block newBlockWithData(boolean readahead) {
   550→            // We need to create a new block with consistent data to avoid duplicated release or leak,
   551→            // cause of the loaded data maybe evicted and reloaded.
   552→            Block newBlock = new Block(metadata, index);
   553→            ObjectReader objectReader = objectReaderFactory.get(metadata);
   554→            DataBlockCache.GetOptions getOptions = DataBlockCache.GetOptions.builder().readahead(readahead).build();
   555→            loadCf = dataBlockCache.getBlock(getOptions, objectReader, index).thenAccept(newData -> {
   556→                newBlock.data = newData;
   557→                if (!readCompleted && data != newData) {
   558→                    // the data block is first loaded or evict & reload
   559→                    if (data != null) {
   560→                        freeListenerHandle.close();
   561→                    }
   562→                    data = newData;
   563→                    newData.markUnread();
   564→                    freeListenerHandle = data.registerFreeListener(b -> handleBlockFree(this));
   565→                }
   566→            }).exceptionally(ex -> {
   567→                exception = ex;
   568→                newBlock.exception = ex;
   569→                return null;
   570→            }).whenComplete((nil, ex) -> objectReader.release());
   571→            newBlock.loadCf = loadCf;
   572→            return newBlock;
   573→        }
   574→
   575→        public void release() {
   576→            if (released) {
   577→                return;
   578→            }
   579→            released = true;
   580→            loadCf.whenComplete((nil, ex) -> {
   581→                if (data != null) {
   582→                    data.release();
   583→                }
   584→            });
   585→        }
   586→
   587→        /**
   588→         * The <code>Block#markReadCompleted</code> should be invoked after the Block was removed from <code>blocksMap</code>.
   589→         */
   590→        public void markReadCompleted() {
   591→            readCompleted = true;
   592→            if (data != null) {
   593→                data.markRead();
   594→                freeListenerHandle.close();
   595→            }
   596→        }
   597→
   598→        @Override
   599→        public String toString() {
   600→            return "Block{" +
   601→                "metadata=" + metadata +
   602→                ", index=" + index +
   603→                ", data=" + data +
   604→                ", exception=" + exception +
   605→                ", released=" + released +
   606→                '}';
   607→        }
   608→    }
   609→
   610→    class Readahead {
   611→        long nextReadaheadOffset;
   612→        int nextReadaheadSize = READAHEAD_SIZE_UNIT;
   613→        long readaheadMarkOffset;
   614→        long resetTimestamp;
   615→        boolean requireReset;
   616→        volatile CompletableFuture<Void> inflightReadaheadCf;
   617→        private int cacheMissCount;
   618→
   619→        public void tryReadahead(boolean cacheMiss) {
   620→            if (System.currentTimeMillis() - resetTimestamp < READAHEAD_RESET_COLD_DOWN_MILLS) {
   621→                // skip readahead when readahead is in cold down
   622→                return;
   623→            }
   624→            cacheMissCount += cacheMiss ? 1 : 0;
   625→            if (inflightReadaheadCf != null) {
   626→                return;
   627→            }
   628→            nextReadaheadSize = Math.min(nextReadaheadSize + cacheMissCount * READAHEAD_SIZE_UNIT, MAX_READAHEAD_SIZE);
   629→            cacheMissCount = 0;
   630→            if (requireReset) {
   631→                nextReadaheadOffset = 0L;
   632→                nextReadaheadSize = READAHEAD_SIZE_UNIT;
   633→                readaheadMarkOffset = 0L;
   634→                requireReset = false;
   635→            }
   636→            if (nextReadOffset >= nextReadaheadOffset) {
   637→                nextReadaheadOffset = nextReadOffset;
   638→            } else if (nextReadOffset <= readaheadMarkOffset) {
   639→                // if the user read doesn't reach the readahead mark, we don't need to readahead
   640→                return;
   641→            }
   642→            if (dataBlockCache.available() < nextReadaheadSize + READAHEAD_AVAILABLE_BYTES_THRESHOLD) {
   643→                return;
   644→            }
   645→            readaheadMarkOffset = nextReadaheadOffset;
   646→            inflightReadaheadCf = getBlocks(nextReadaheadOffset, -1L, nextReadaheadSize, true).thenAccept(blocks -> {
   647→                nextReadaheadOffset = blocks.isEmpty() ? nextReadaheadOffset : blocks.get(blocks.size() - 1).index.endOffset();
   648→                blocks.forEach(Block::release);
   649→            });
   650→            // For get block indexes and load data block are sync success,
   651→            // the whenComplete will invoke first before assign CompletableFuture to inflightReadaheadCf
   652→            inflightReadaheadCf.whenComplete((nil, ex) -> {
   653→                Throwable cause = FutureUtil.cause(ex);
   654→                if (cause != null && !isRecoverable(cause)) {
   655→                    LOGGER.error("Readahead failed", ex);
   656→                }
   657→                inflightReadaheadCf = null;
   658→            });
   659→        }
   660→
   661→        public void reset() {
   662→            requireReset = true;
   663→            resetTimestamp = System.currentTimeMillis();
   664→        }
   665→    }
   666→
   667→}
