        doAnswer(args -> {
            if (failed.get()) {
                return true;
            } else {
                failed.set(true);
                return false;
            }
        }).when(objectManager).isObjectExist(anyLong());
        eventLoops[0].submit(() -> readCf.set(streamReader.read(14L, 15L, Integer.MAX_VALUE))).get();

