        if (afterReadTryReadaheadCf != null) {
            afterReadTryReadaheadCf.get();
        }

        CompletableFuture<Void> inflightReadaheadCf = streamReader.getReadaheadInflightReadaheadCf();
        if (inflightReadaheadCf != null) {
            inflightReadaheadCf.get();
        }
    }

