        // object=3 [9, 14)
        // object=4 [14, 19)
        // object=5 [19, 24)
        // object=6 [24, 29)
        // object=7 [29, 34)
        objects.put(0L, MockObject.builder(0, BLOCK_SIZE_THRESHOLD).mockDelay(100).write(STREAM_ID, List.of(
            new StreamRecordBatch(STREAM_ID, 0, 0, 1, TestUtils.random(1))
